/****** Object:  StoredProcedure [dbo].[Usp_DynamicChatBot]    Script Date: 02-04-2026 09:48:14 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE Proc [dbo].[Usp_DynamicChatBot]
as
begin


SELECT i.IntentCode, k.Keyword,CAST(k.KeywordID AS INT) KeywordID,CAST(k.IntentId AS INT) IntentId
          FROM Tbl_BotIntentKeywords k
          JOIN Tbl_BotIntentMaster i ON i.IntentId = k.IntentId


end

GO
/****** Object:  StoredProcedure [dbo].[Usp_ExecuteAction]    Script Date: 02-04-2026 09:48:14 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE proc [dbo].[Usp_ExecuteAction]
(
@IntentId int=null
)
as
BEGIN

SELECT a.ActionType, a.SqlQuery,CAST(ia.IntentId as INT) IntentId
,CAST(a.ActionId as int)ActionId FROM Tbl_BotIntentAction ia JOIN Tbl_BotAction a ON a.ActionId = 
ia.ActionId WHERE ia.IntentId = @IntentId

END
GO
