/****** Object:  StoredProcedure [dbo].[Usp_GetGuestCount]    Script Date: 02-04-2026 09:48:14 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[Usp_GetGuestCount]
    @UserId INT
AS
BEGIN
    SELECT ISNULL(COUNT(*),0)
    FROM Tbl_Guest G
    INNER JOIN Tbl_Flat F ON G.FID = F.FID
    WHERE F.LoginID = @UserId
    AND MONTH(G.CreatedDateTime)=MONTH(GETDATE())
    AND YEAR(G.CreatedDateTime)=YEAR(GETDATE())
END
GO
