/****** Object:  StoredProcedure [dbo].[Usp_GetLastGuest]    Script Date: 02-04-2026 09:48:14 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[Usp_GetLastGuest]
    @UserId INT
AS
BEGIN
    SELECT TOP 1
        CONCAT(
            'Name: ', GName,
            ' | Mobile: ', GMobile,
            ' | Date: ', FORMAT(G.CreatedDateTime,'dd-MMM-yyyy')
        )
    FROM Tbl_Guest G
    INNER JOIN Tbl_Flat F ON G.FID = F.FID
    WHERE F.LoginID = @UserId
    ORDER BY G.CreatedDateTime DESC
END
GO
/****** Object:  StoredProcedure [dbo].[Usp_GetLastPayment]    Script Date: 02-04-2026 09:48:14 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
Create proc [dbo].[Usp_GetLastPayment]
(
@UserId int
)
as
BEGIN
    Select top 1 CONCAT('Pay Amount:- ','(',Amount,')' , '| Pay Status:- ','(',TranStatus,')',' | Pay Date:- ' , '(',FORMAT(PaymentDate,'dd-MMM-yyyy'),')') from Tbl_PaymentTransactions P JOIN Tbl_Flat F ON F.FID=P.FlatID where LoginID=@UserId AND TranStatus='Approved' order by PaymentDate desc
END
GO
