GO
SET QUOTED_IDENTIFIER ON
GO
Create proc [dbo].[Usp_GetmyParking]
(
@UserId int
)
as
BEGIN
SELECT Concat(String_AGG(Concat('Slot -',SlotNumber,' /'),', '), STRING_AGG(VehicleNumber,' ,'))
FROM Tbl_Parking P JOIN Tbl_Flat F ON P.FID=F.FID WHERE F.LoginID=@UserId
END
GO
