GO
SET QUOTED_IDENTIFIER ON
GO
Create proc [dbo].[Usp_GetTotalTransaction]
(
@UserId int
)
as
BEGIN
Select SUM(Amount) TotalAmount From Tbl_PaymentTransactions P JOIN Tbl_Flat F ON P.FlatID=F.FID
WHERE F.LoginID=@UserId AND P.TranStatus='Approved'
END
GO
/****** Object:  StoredProcedure [dbo].[USP_Tbl_ErrorLogs]    Script Date: 02-04-2026 09:48:14 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE proc [dbo].[USP_Tbl_ErrorLogs]
(
@ERRID bigint=null,
@ErrorPage nvarchar(max)=null,
@ErrorStack nvarchar(max)=null,
@ErrorMessage nvarchar(max)=null,
@ErrorLoggedByID Varchar(max)=null,
@ErrorLoggedByName varchar(max)=null,
@Flag Varchar(100)=null
)
AS
BEGIN
IF(@Flag='IN')
BEGIN
INSERT INTO Tbl_ErrorLogs(
[ErrorPage], [ErrorStack], [ErrorMessage], [ErrorLoggedByID], [ErrorLoggedByName]
)
OUTPUT INSERTED.*
VALUES
(@ErrorPage, @ErrorStack, @ErrorMessage, @ErrorLoggedByID, @ErrorLoggedByName)
END
ELSE IF(@Flag='Report')
BEGIN


Select * from [dbo].[Tbl_ErrorLogs] where [IsResolve]=0 Order by 1 desc

END

END
GO
/****** Object:  StoredProcedure [dbo].[USP_Tbl_FCMToken]    Script Date: 02-04-2026 09:48:14 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROC [dbo].[USP_Tbl_FCMToken]
(
@FCID bigint=null,
@FlatID Int=null,
@FcmToken varchar(max)=null,
@UpdatedOn datetime=null
)
AS
BEGIN

INSERT INTO Tbl_FCMToken (FlatID,FcmToken,UpdatedOn)
VALUES (@FlatID,@FcmToken,GETDATE())

SET @FCID=  IDENT_CURRENT('Tbl_FCMToken');

