/****** Object:  StoredProcedure [dbo].[usp_Tbl_PaymentTransactions]    Script Date: 02-04-2026 09:48:14 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE    PROCEDURE [dbo].[usp_Tbl_PaymentTransactions]
(
   @Flag        CHAR(20),        -- IN / UP / SE

    @Id          BIGINT = NULL,
    @Amount      DECIMAL(18,2) = NULL,
    @UTR         VARCHAR(2000) = NULL,          -- UTR is numeric/alphanumeric → VARCHAR OK
    @PaidTo      NVARCHAR(2000) = NULL,        -- FIXED
    @PaymentDate DATETIME = NULL,
    @SourceApp   NVARCHAR(50) = NULL,         -- FIXED
    @RawText     NVARCHAR(MAX) = NULL,        -- ALREADY CORRECT
    @TranStatus  VARCHAR(200) = NULL,
    @FlatID      BIGINT = NULL,
    @UID BIGINT=NULL,
    @Remark nvarchar(max)=null
)
AS
BEGIN
    SET NOCOUNT ON;

    Declare @PrivList_find nvarchar(max)


    /* =========================
       INSERT
       ========================= */
    IF @Flag = 'IN'
    BEGIN
    
        INSERT INTO Tbl_PaymentTransactions
        (
            Amount,
            UTR,
            PaidTo,
            PaymentDate,
            SourceApp,
            RawText,
            FlatID,
            TranStatus,
            CreadedBY
        )
        VALUES
        (
            @Amount,
            @UTR,
            @PaidTo,
            @PaymentDate,
            @SourceApp,
            @RawText,
            @FlatID,
            'New',
            @UID
            
        );

        SELECT  
            Id,
            Amount,
            UTR,
            PaidTo,
            PaymentDate,
            SourceApp,
            RawText,
            CreatedOn,
            FlatID,
            TranStatus,
            Remark,
            '' FlatMobile,
            '' Uname
        FROM Tbl_PaymentTransactions
        WHERE Id = SCOPE_IDENTITY();
    END
    
    /* =========================
       UPDATE
       ========================= */
    ELSE IF @Flag = 'UP'
    BEGIN
        UPDATE Tbl_PaymentTransactions
        SET
            Amount      = @Amount,
            UTR         = @UTR,
            PaidTo      = @PaidTo,
            PaymentDate = @PaymentDate,
            SourceApp   = @SourceApp,
            RawText     = @RawText,
            FlatID      = @FlatID,
            TranStatus=@TranStatus,
            ModifiedBY=@UID,
            Remark=@Remark

        WHERE Id = @Id;

        SELECT
            Id,
            Amount,
            UTR,
            PaidTo,
            PaymentDate,
            SourceApp,
            RawText,
            CreatedOn,
            FlatID,
            TranStatus,
            Remark,
            '' FlatMobile,
            '' Uname
            FROM Tbl_PaymentTransactions
        WHERE Id = @Id;
    END

    /* =========================
       SELECT
       ========================= */
    ELSE IF @Flag = 'Report'
    BEGIN
    SET @PrivList_find = (Select PrivList from Tbl_User where UID=@UID)

IF(CHARINDEX('Admin|SuperAdmin|Developer',@PrivList_find)>0)
BEGIN
      SELECT
            Id,
            Amount,
            UTR,
            PaidTo,
            PaymentDate,
            SourceApp,
            RawText,
            CreatedOn,
            FlatID,
            TranStatus,
            Remark,
            U.UMobile FlatMobile,
            U.UName Uname
        FROM Tbl_PaymentTransactions P JOIN 
        Tbl_Flat F
        ON P.FlatID = F.FID
        JOIN Tbl_User U 
        ON U.UID = F.LoginID
        WHERE ISNULL(FlatID,'') <> '' 
           

        ORDER BY CreatedOn DESC;
        END
ELSE 
BEGIN
 SELECT
            Id,
            Amount,
            UTR,
            PaidTo,
            PaymentDate,
            SourceApp,
            RawText,
            CreatedOn,
            FlatID,
            TranStatus,
            Remark,
            U.UMobile FlatMobile,
            U.UName Uname
        FROM Tbl_PaymentTransactions P JOIN 
        Tbl_Flat F
        ON P.FlatID = F.FID
        JOIN Tbl_User U 
        ON U.UID = F.LoginID
        WHERE ISNULL(FlatID,'') <> '' 
           AND FlatID=@FlatID

        ORDER BY CreatedOn DESC;

END

    END
    ELSE
    BEGIN
        THROW 50001, 'Invalid Flag. Use IN, UP or SE', 1;
    END
END;
GO
